<?php
namespace App\Http\Requests\Admin\Content;use App\Domain\Inventory\ItemClassification;use App\Domain\Probability\PercentagePpmConverter;use App\Domain\WorldCatalog\CatalogStatus;use App\Models\Item;use Illuminate\Foundation\Http\FormRequest;use Illuminate\Validation\Rule;use InvalidArgumentException;
class LootEntryRequest extends FormRequest{protected function prepareForValidation(){$value=$this->input('drop_probability_percent');$ppm=-1;if(is_string($value)){try{$ppm=app(PercentagePpmConverter::class)->toPpm($value);}catch(InvalidArgumentException $e){}}$this->merge(['drop_probability_ppm'=>$ppm]);}public function authorize(){return true;}public function rules(){$monster=$this->route('monster');$entry=$this->route('lootEntry');$unique=Rule::unique('monster_loot_entries','item_id')->where(function($query)use($monster){return$query->where('monster_id',$monster->id);});if($entry)$unique->ignore($entry->id);return['item_id'=>['required','integer','exists:items,id',$unique],'drop_probability_percent'=>['required','string',function($attribute,$value,$fail){try{app(PercentagePpmConverter::class)->toPpm($value);}catch(InvalidArgumentException $e){$fail('La probabilidad debe ser un porcentaje entre 0 y 100 con hasta cuatro decimales.');}}],'drop_probability_ppm'=>'required|integer|min:0|max:1000000','minimum_quantity'=>'required|integer|min:1','maximum_quantity'=>'required|integer|min:1|gte:minimum_quantity','status'=>['required',Rule::in(CatalogStatus::values())],'sort_order'=>'required|integer|min:0'];}public function lootData(){$data=$this->validated();unset($data['drop_probability_percent']);return$data;}public function withValidator($validator){$validator->after(function($validator){if($validator->errors()->has('item_id')||$validator->errors()->has('minimum_quantity')||$validator->errors()->has('maximum_quantity'))return;$item=Item::find($this->input('item_id'));if(!$item)return;try{$kind=app(ItemClassification::class)->classify($item);if($kind===ItemClassification::UNIQUE&&((int)$this->input('minimum_quantity')!==1||(int)$this->input('maximum_quantity')!==1))$validator->errors()->add('maximum_quantity','Los objetos no apilables requieren cantidad mínima y máxima igual a 1.');}catch(InvalidArgumentException $e){$validator->errors()->add('item_id',$e->getMessage());}});}}
